import boto3
from botocore.exceptions import NoCredentialsError, PartialCredentialsError

def publish_sqs_message(queue_url, user_data):
    # Initialize a session using Amazon SQS
    sqs = boto3.client('sqs')
    
    try:
        # Send message to SQS queue
        response = sqs.send_message(
            QueueUrl=queue_url,
            MessageBody=user_data
        )
        print("Message sent successfully. Message ID:", response['MessageId'])
    except NoCredentialsError:
        print("Credentials not available")
    except PartialCredentialsError:
        print("Incomplete credentials provided")
    except Exception as e:
        print(f"An error occurred: {e}")

# Example usage
queue_url = 'https://sqs.us-east-1.amazonaws.com/123456789012/my-queue'
user_data = '{"email": "example@example.com", "phone": "123-456-7890", "address": "123 Main St"}'

publish_sqs_message(queue_url, user_data)